    pub link_fn: LF,
    pub inverse_link_fn: ILF,
    pub mu_eta_fn: MEF,
    pub variance_fn: VF,
    pub dev_resid_fn: DR,
}

impl Default for IrlsConfig {
    fn default() -> Self {
        Self {
            max_iter: 25,
            tolerance: 1e-8,
            min_weight: 1e-8,
        }
    }
