use ndarray_linalg::LeastSquares;

fn solve_weighted_least_squares(
    x: &ArrayView2<f64>,
    z: &Array1<f64>,
    weights: &Array1<f64>,
    x_weighted: &mut Array2<f64>, // Buffer
    z_weighted: &mut Array1<f64>, // Buffer
) -> Result<Array1<f64>, OptimError> {
    let sqrt_weights = weights.mapv(f64::sqrt);

    // Update buffers in place instead of allocating
    // (See next issue for vectorizing this part)
    for i in 0..x.nrows() {
        for j in 0..x.ncols() {
